<!DOCTYPE html>

<html class="light" lang="es">

<head>
    <meta charset="utf-8" />
    <meta content="width=device-width, initial-scale=1.0" name="viewport" />
    <title>SIT-EPS - Iniciar Sesión</title>
    <script src="https://cdn.tailwindcss.com?plugins=forms,container-queries"></script>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&amp;display=swap"
        rel="stylesheet" />
    <link
        href="https://fonts.googleapis.com/css2?family=Material+Symbols+Outlined:wght,FILL@100..700,0..1&amp;display=swap"
        rel="stylesheet" />
    <link
        href="https://fonts.googleapis.com/css2?family=Material+Symbols+Outlined:wght,FILL@100..700,0..1&amp;display=swap"
        rel="stylesheet" />
    <script id="tailwind-config">
        tailwind.config = {
            darkMode: "class",
            theme: {
                extend: {
                    "colors": {
                        "surface-variant": "#d3e4fe",
                        "on-error-container": "#93000a",
                        "inverse-surface": "#213145",
                        "secondary-fixed": "#d3e4ff",
                        "on-secondary-fixed-variant": "#004881",
                        "tertiary-container": "#005713",
                        "primary": "#00355f",
                        "on-primary-fixed": "#001c37",
                        "on-surface": "#0b1c30",
                        "error-container": "#ffdad6",
                        "on-tertiary-fixed-variant": "#005312",
                        "on-tertiary-container": "#7ccd77",
                        "tertiary-fixed": "#a3f69c",
                        "outline": "#727780",
                        "on-primary-container": "#8ebdf9",
                        "on-primary-fixed-variant": "#07497d",
                        "surface": "#f8f9ff",
                        "surface-container": "#e5eeff",
                        "inverse-primary": "#a0c9ff",
                        "on-secondary": "#ffffff",
                        "on-surface-variant": "#42474f",
                        "on-error": "#ffffff",
                        "on-primary": "#ffffff",
                        "primary-container": "#0f4c81",
                        "inverse-on-surface": "#eaf1ff",
                        "secondary": "#0060a8",
                        "surface-dim": "#cbdbf5",
                        "on-secondary-fixed": "#001c38",
                        "on-tertiary-fixed": "#002204",
                        "on-background": "#0b1c30",
                        "background": "#f8f9ff",
                        "tertiary": "#003d0b",
                        "secondary-container": "#47a1ff",
                        "surface-container-high": "#dce9ff",
                        "surface-bright": "#f8f9ff",
                        "primary-fixed-dim": "#a0c9ff",
                        "tertiary-fixed-dim": "#88d982",
                        "surface-container-lowest": "#ffffff",
                        "on-tertiary": "#ffffff",
                        "outline-variant": "#c2c7d1",
                        "surface-tint": "#2d6197",
                        "error": "#ba1a1a",
                        "surface-container-low": "#eff4ff",
                        "primary-fixed": "#d2e4ff",
                        "secondary-fixed-dim": "#a2c9ff",
                        "on-secondary-container": "#003663",
                        "surface-container-highest": "#d3e4fe"
                    },
                    "borderRadius": {
                        "DEFAULT": "0.25rem",
                        "lg": "0.5rem",
                        "xl": "0.75rem",
                        "2xl": "12px",
                        "full": "9999px"
                    },
                    "spacing": {
                        "container-max": "1280px",
                        "xs": "4px",
                        "2xl": "48px",
                        "lg": "24px",
                        "unit": "4px",
                        "gutter": "16px",
                        "xl": "32px",
                        "sm": "8px",
                        "md": "16px"
                    },
                    "fontFamily": {
                        "headline-lg": ["Inter"],
                        "body-lg": ["Inter"],
                        "title-lg": ["Inter"],
                        "body-md": ["Inter"],
                        "display-lg": ["Inter"],
                        "label-md": ["Inter"],
                        "headline-lg-mobile": ["Inter"]
                    },
                    "fontSize": {
                        "headline-lg": ["32px", { "lineHeight": "40px", "letterSpacing": "-0.01em", "fontWeight": "600" }],
                        "body-lg": ["16px", { "lineHeight": "24px", "fontWeight": "400" }],
                        "title-lg": ["20px", { "lineHeight": "28px", "fontWeight": "600" }],
                        "body-md": ["14px", { "lineHeight": "20px", "fontWeight": "400" }],
                        "display-lg": ["48px", { "lineHeight": "56px", "letterSpacing": "-0.02em", "fontWeight": "700" }],
                        "label-md": ["12px", { "lineHeight": "16px", "letterSpacing": "0.05em", "fontWeight": "500" }],
                        "headline-lg-mobile": ["24px", { "lineHeight": "32px", "fontWeight": "600" }]
                    }
                },
            },
        }
    </script>
    <style>
        .material-symbols-outlined {
            font-variation-settings: 'FILL' 0, 'wght' 400, 'GRAD' 0, 'opsz' 24;
        }

        .glass-panel {
            backdrop-filter: blur(12px);
            background-color: rgba(255, 255, 255, 0.8);
        }

        .form-input-focus:focus {
            outline: none;
            border-color: #1E88E5;
            box-shadow: 0 0 0 2px rgba(30, 136, 229, 0.2);
        }
    </style>
</head>

<body class="bg-surface font-body-md text-on-surface h-screen overflow-hidden">
    <main class="flex h-full w-full">
        <!-- Left Side: Login Form -->
        <section
            class="w-full lg:w-1/2 flex flex-col justify-center items-center p-lg lg:p-2xl bg-surface-container-lowest relative z-10">
            <div class="w-full max-w-md">
                <!-- Brand Identity -->
                <div class="flex flex-col items-center mb-xl">
                    <img alt="SIT-EPS Logo" class="w-24 h-24 mb-md object-contain"
                        src="data:image/png;base64," />
                    <h1 class="font-headline-lg text-headline-lg text-primary text-center mb-xs">Bienvenido a SIT-EPS
                    </h1>
                    <p class="font-body-lg text-body-lg text-on-surface-variant text-center">Gestión inteligente de su
                        salud</p>
                </div>
                <!-- Login Form -->
                <form class="space-y-md" onsubmit="return false;">
                    <!-- Email Field -->
                    <div class="space-y-xs">
                        <label class="font-label-md text-label-md text-on-surface-variant ml-xs" for="email">Correo
                            electrónico</label>
                        <div class="relative">
                            <span
                                class="material-symbols-outlined absolute left-md top-1/2 -translate-y-1/2 text-outline-variant">mail</span>
                            <input
                                class="w-full h-14 pl-12 pr-md bg-surface border border-outline-variant rounded-2xl font-body-md text-on-surface form-input-focus transition-all duration-200"
                                id="email" placeholder="nombre@ejemplo.com" type="email" />
                        </div>
                    </div>
                    <!-- Password Field -->
                    <div class="space-y-xs">
                        <label class="font-label-md text-label-md text-on-surface-variant ml-xs"
                            for="password">Contraseña</label>
                        <div class="relative">
                            <span
                                class="material-symbols-outlined absolute left-md top-1/2 -translate-y-1/2 text-outline-variant">lock</span>
                            <input
                                class="w-full h-14 pl-12 pr-12 bg-surface border border-outline-variant rounded-2xl font-body-md text-on-surface form-input-focus transition-all duration-200"
                                id="password" placeholder="••••••••" type="password" />
                            <button
                                class="absolute right-md top-1/2 -translate-y-1/2 text-outline-variant hover:text-primary transition-colors"
                                type="button">
                                <span class="material-symbols-outlined">visibility</span>
                            </button>
                        </div>
                    </div>
                    <!-- Remember & Forgot -->
                    <div class="flex items-center justify-between px-xs py-xs">
                        <label class="flex items-center space-x-sm cursor-pointer group">
                            <input class="w-5 h-5 rounded border-outline-variant text-primary focus:ring-primary"
                                type="checkbox" />
                            <span
                                class="font-body-md text-on-surface-variant group-hover:text-on-surface transition-colors">Recordarme</span>
                        </label>
                        <a class="font-label-md text-label-md text-secondary hover:underline transition-all"
                            href="#">¿Olvidaste tu contraseña?</a>
                    </div>
                    <!-- Submit Button -->
                    <button
                        class="w-full h-14 bg-primary-container text-on-primary font-title-lg text-title-lg rounded-2xl shadow-sm hover:opacity-90 active:scale-[0.98] transition-all flex items-center justify-center space-x-sm mt-md"
                        type="submit">
                        <span>Iniciar sesión</span>
                    </button>
                    <!-- AI Suggestion Prompt (Minimalist Cues) -->
                    <div
                        class="mt-xl p-md bg-surface-container rounded-2xl border border-primary/5 flex items-start gap-md">
                        <span class="material-symbols-outlined text-primary"
                            style="font-variation-settings: 'FILL' 1;">auto_awesome</span>
                        <div class="space-y-xs">
                            <p class="font-label-md text-label-md text-primary font-bold uppercase tracking-wider">
                                Acceso Seguro</p>
                            <p class="font-body-md text-on-surface-variant">Nuestro sistema utiliza inteligencia
                                artificial para monitorear intentos de acceso inusuales y proteger su información médica
                                privada.</p>
                        </div>
                    </div>
                </form>
                <!-- Footer Links -->
                <div class="mt-2xl text-center">
                    <p class="font-body-md text-on-surface-variant">
                        ¿Aún no tiene una cuenta?
                        <a class="text-secondary font-bold hover:underline" href="#">Solicitar acceso</a>
                    </p>
                </div>
            </div>
        </section>
        <!-- Right Side: Visual Section -->
        <section class="hidden lg:block w-1/2 relative bg-surface-variant overflow-hidden">
            <!-- Background Image with Overlay -->
            <div class="absolute inset-0 z-0 bg-cover bg-center transition-transform duration-10000 hover:scale-110"
                data-alt="A professional and welcoming medical environment featuring a high-tech diagnostic room with soft lighting. In the foreground, a friendly healthcare professional is interacting with a digital interface that shows stylized health data and AI pulse lines. The atmosphere is calm, empathetic, and technologically advanced, using a palette of clinical whites, soft blues, and deep indigo accents. High-end modern photography style with a shallow depth of field."
                style="background-image: url('https://lh3.googleusercontent.com/aida-public/AB6AXuBY_zWtZCTLUrCrTrO5UENhqyVcnOSg1zyq8UNEFW58StyKUFeXOx_oMEIm9asq8BFcg87YMi7jhRIL78z3H2MkOVEFpgQ1MD8tvf6As_i12KNVOXRvuIofMVoXh4_m0y2fcFXiLf_5ZYaPqrZSZO1JobT6uFkFEYbM03I5pQmUd8lH21fW_ROumyIOuUWAZtVRZzkq1A_IFCURJEHSZJ72PQdr1eKQXfkrxcVTT_oVjK730yj-c9rAsc2FmFGoVu0P8ztefKXj3k0')">
            </div>
            <!-- Atmospheric Gradient Overlay -->
            <div class="absolute inset-0 z-10 bg-gradient-to-tr from-primary/80 via-primary/20 to-transparent"></div>
            <!-- Content on Image -->
            <div class="absolute inset-0 z-20 flex flex-col justify-end p-2xl">
                <div class="glass-panel p-xl rounded-2xl border border-white/20 max-w-lg shadow-2xl">
                    <div class="flex items-center gap-sm mb-md">
                        <span class="material-symbols-outlined text-on-secondary-container"
                            style="font-variation-settings: 'FILL' 1;">verified_user</span>
                        <span
                            class="font-label-md text-label-md text-on-secondary-container bg-secondary-container/50 px-sm py-xs rounded-full">Protección
                            Nivel Hospitalario</span>
                    </div>
                    <h2 class="font-headline-lg text-headline-lg text-on-background mb-md">Su salud, nuestra prioridad
                        inteligente.</h2>
                    <p class="font-body-lg text-body-lg text-on-surface-variant">
                        Bienvenido al ecosistema SIT-EPS. Integramos diagnóstico predictivo y gestión clínica avanzada
                        para brindarle una experiencia de salud sin precedentes.
                    </p>
                    <div class="mt-xl flex items-center gap-xl">
                        <div class="flex -space-x-md">
                            <!-- Faux Avatars for Social Proof -->
                            <div class="w-10 h-10 rounded-full border-2 border-white bg-cover bg-center"
                                data-alt="Close-up portrait of a professional female doctor in a white lab coat, smiling confidently, high-key lighting, medical office background."
                                style="background-image: url('https://lh3.googleusercontent.com/aida-public/AB6AXuBj_WhTXDa2l9nNuFyjAyNKPI2QYWysrhsqV4Ehn9_AjSMvKlhP_TV_0ILpvLe3sqYkX6SuSi3TQmbnCP2iDzDK8OKiDTSMu9eZwI0h_UXq-xXOsvtd0LDIDkYmy8-h2b5xDlNNQ-9abFURlwJd4OiPaZstCpBOPhU4KJyevTjhxNQsB2wzSPlwThQlxvx-DonwmjeTn3JgGwIcdQlrFBylePy_75ECHl2fOqTvOPRL0zAWjzPqHK1bahQ6zdV99zAaMc4xkfE9XhM')">
                            </div>
                            <div class="w-10 h-10 rounded-full border-2 border-white bg-cover bg-center"
                                data-alt="Close-up portrait of a middle-aged male physician with glasses, looking professional and trustworthy, clinical setting, soft natural lighting."
                                style="background-image: url('https://lh3.googleusercontent.com/aida-public/AB6AXuDKY0tefrK1A_2EgWsz7AmJ4Vj8kmrfF49zdt0L21KtU9YYXeNSIGWtEX3aXgGh_QnCCu8NrU5dXT9eFjo1hQpZT2N3X9ru0MTt0UtAACE-DIN481rOfJMcz8X4Yd9oK5JArboAikmAmnCOSHpErMu89hXq5lxSC0QRGQKoqK2Q_Xmga9J9_0gSj1DpNpmtPNTCfg_nnqH8RrBDIJexsB7RHlgVpP-iJF4rQ2egedsDRMv_STecglX6IwPySorSu22rtRC4IImCWHY')">
                            </div>
                            <div class="w-10 h-10 rounded-full border-2 border-white bg-cover bg-center"
                                data-alt="Close-up portrait of a young medical researcher, professional attire, modern laboratory background, clean minimalist aesthetic."
                                style="background-image: url('https://lh3.googleusercontent.com/aida-public/AB6AXuBj6nXlU0MFnPaUR0H1aRyeBGJSIkjPHMTIa2MJZ40h9JvlOx1g9djv0uDSaiGkGrIa0L6s2wPsuKHxQSkgcBUrpgTRkBrUovjO5MGtZvqB91rMM_FyuuKPxh92BAERDpPPAi67_ddSn1ETeCPq1OSa_XzqscAWgYV4XsXshw8kq4W1hOl8fjyWzyu1tAdUtWeIUP7qYdnpLyzS2AlS4sihk9qhLVpXomBNhGLJSfooPEn8bG4CIjiR4tg2xBGCIl_n56osv7I8n5A')">
                            </div>
                        </div>
                        <p class="font-label-md text-label-md text-on-surface-variant">Confianza de más de 500
                            profesionales de la salud.</p>
                    </div>
                </div>
            </div>
            <!-- Floating AI Sparkles Effect -->
            <div class="absolute top-10 right-10 z-20 pointer-events-none opacity-40">
                <span class="material-symbols-outlined text-white text-[80px]"
                    style="font-variation-settings: 'FILL' 0, 'wght' 100;">auto_awesome</span>
            </div>
        </section>
    </main>
    <!-- Micro-interaction Script -->
    <script>
        document.addEventListener('DOMContentLoaded', () => {
            const togglePassword = document.querySelector('button[type="button"]');
            const passwordInput = document.getElementById('password');

            togglePassword.addEventListener('click', () => {
                const type = passwordInput.getAttribute('type') === 'password' ? 'text' : 'password';
                passwordInput.setAttribute('type', type);
                togglePassword.querySelector('span').textContent = type === 'password' ? 'visibility' : 'visibility_off';
            });

            // Smooth scale interaction for buttons
            const buttons = document.querySelectorAll('button');
            buttons.forEach(btn => {
                btn.addEventListener('mousedown', () => btn.classList.add('scale-95'));
                btn.addEventListener('mouseup', () => btn.classList.remove('scale-95'));
                btn.addEventListener('mouseleave', () => btn.classList.remove('scale-95'));
            });
        });
    </script>
</body>

</html>